const emptyOpp = () => ({ id: Date.now() + Math.random(), name:"", expediente:"", titularName:"", classes:[], products:"", logoPreview:null, regDate:"", territory:"", wellKnown:false, wellKnownTerritory:"", isTradeName:false });
const toggleArr = (arr, set, n) => set(arr.includes(n) ? arr.filter(x=>x!==n) : [...arr,n]);

function Gauge({ pct }) {
  const r=44, cx=55, cy=55, circ=2*Math.PI*r;
  const color = pct>=70?"#276048":pct>=40?"#C07820":"#9B2C2C";
  const filled = circ*(pct/100);
  return (
    <svg viewBox="0 0 110 110">
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#E3E2DD" strokeWidth="9"/>
      <circle cx={cx} cy={cy} r={r} fill="none" stroke={color} strokeWidth="9"
        strokeDasharray={`${filled} ${circ-filled}`} strokeDashoffset={circ*0.25}
        strokeLinecap="round" style={{transition:"stroke-dasharray .7s ease"}}/>
    </svg>
  );
}

