  /* ── API CALL helper ── */
  const callClaude = async (systemPrompt, userContent) => {
    // Step 1: Submit job
    const res = await fetch("/api/claude", {
      method:"POST", headers:{"Content-Type":"application/json"},
      body:JSON.stringify({ systemPrompt, userContent })
    });
    const startData = await res.json();
    if (startData.error) throw new Error(startData.error);
    // If server returned text directly (fallback), use it
    if (startData.text !== undefined) return startData.text || "";
    // Step 2: Poll for result
    const jobId = startData.jobId;
    if (!jobId) throw new Error("No job ID returned");
    const maxWait = 300000; // 5 minutes
    const interval = 3000; // poll every 3 seconds
    const start = Date.now();
    while (Date.now() - start < maxWait) {
      await new Promise(r => setTimeout(r, interval));
      try {
        const pollRes = await fetch(`/api/claude-poll?id=${jobId}`);
        const pollData = await pollRes.json();
        if (pollData.status === "done") return pollData.text || "";
        if (pollData.status === "error") throw new Error(pollData.error || "Generation failed");
        // still processing, continue polling
      } catch (e) {
        if (e.message && !e.message.includes("Failed to fetch")) throw e;
        // network glitch, keep polling
      }
    }
    throw new Error("Generation timed out. Please try again.");
  };

